// Set up cookie expiration date for 30 days
function getCookieExpirationDate() {
    const date = new Date();
    const expires = new Date(date.getTime() + (30 * 24 * 60 * 60 * 1000));
    return expires.toUTCString();
}

// Function to store username and password hash in a cookie
function rememberMe(username, passwordHash) {
    const cookieExpirationDate = getCookieExpirationDate();
    document.cookie = `username=${username}; expires=${cookieExpirationDate}; path=/`;
    document.cookie = `passwordHash=${passwordHash}; expires=${cookieExpirationDate}; path=/`;
}

// Function to auto-login using cookie data
function autoLogin() {
    const username = getCookie('username');
    const passwordHash = getCookie('passwordHash');

    if (username && passwordHash) {
        // Simulate login with cookie data
        console.log(`Auto-login successful for user ${username}`);
        // Redirect to protected area or perform other actions as needed
    }
}

// Helper function to get a cookie value
function getCookie(name) {
    const regex = new RegExp(`${name}=([^;]*)`);
    const match = document.cookie.match(regex);
    return match && match[1];
}